44	  results: (QuoteResult | ClaimResult)[];
45	}
46	
47	const PROCESSING_FEE = 5;
48	
49	const BASE_PREMIUMS: Record<string, number> = {
50	  sword: 100,
51	  amulet: 60,
52	  staff: 80,
53	  potion: 40,
54	  rune: 25,
55	  moonstone: 25,
56	};
57	
58	const COMPONENT_TYPES = ["rune", "moonstone"];
59	const BLOCK_SIZE = 3;
60	const BLOCK_PREMIUM = 60;
61	
62	const isComponent = (item: Item): boolean =>
63	  COMPONENT_TYPES.includes(item.type);
64	
65	const itemBasePremium = (item: Item): number =>
66	  BASE_PREMIUMS[item.type] ?? 0;
67	
68	const itemPremiumWithModifiers = (item: Item): number => {
69	  const base = itemBasePremium(item);
70	  return base
71	    + (item.cursed ? base * 0.5 : 0)
72	    + ((item.enchantment ?? 0) >= 5 ? base * 0.3 : 0);
73	};
74	
75	const regularItems = (items: Item[]): Item[] =>
76	  items.filter((item) => !isComponent(item));
77	
78	const regularItemsPremium = (items: Item[]): number =>
79	  regularItems(items)
80	    .reduce((sum, item) => sum + itemPremiumWithModifiers(item), 0);
81	
82	const componentBlockPremium = (count: number, type: string): number =>
83	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
84	
85	const countByType = (entries: { type: string }[]): Record<string, number> =>
86	  entries.reduce(
87	    (acc: Record<string, number>, entry) => ({
88	      ...acc,
89	      [entry.type]: (acc[entry.type] ?? 0) + 1,
90	    }),
91	    {},
92	  );
93	
94	const countComponentsByType = (items: Item[]): Record<string, number> =>
95	  countByType(items.filter(isComponent));
96	
97	const componentsPremium = (items: Item[]): number =>
98	  Object.entries(countComponentsByType(items)).reduce(
99	    (sum, [type, count]) => sum + componentBlockPremium(count, type),
100	    0,
101	  );
102	
103	const policyBasePremium = (items: Item[]): number =>
104	  regularItems(items)
105	    .reduce((sum, item) => sum + itemBasePremium(item), 0)
106	  + componentsPremium(items);
107	
108	const policyWideModifierRate = (customer: Customer, quoteIndex: number): number =>
109	  0.1 + (customer.yearsWithMHPCO >= 2 ? -0.2 : 0) + (quoteIndex > 0 ? -0.15 : 0);
110	
111	const validateItemTypes = (items: Item[]): void => {
112	  const unknownItem = items.find((item) => !(item.type in BASE_PREMIUMS));
113	  if (unknownItem) {
114	    throw new Error(`Unknown item type: ${unknownItem.type}`);
115	  }
116	};
117	
118	const calculateQuotePremium = (items: Item[], customer: Customer, quoteIndex: number): number => {
